function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The total path length is (m - 1) + (n - 1) + 1 = m + n - 1.
    // The sum of coordinates i + j for any cell (i, j) on a path
    // from (0, 0) to (m-1, n-1) will range from 0 to (m-1) + (n-1).
    const max_sum = m + n - 2;

    // dp[i][j] will store the set of all possible XOR sums to reach cell (i, j).
    // Since m*n <= 1000, this approach might be too slow if the number of paths is large.
    // However, the constraint m*n <= 1000 suggests that a path-based DP or
    // a meet-in-the-middle might be feasible if we leverage the path length structure.

    // Meet-in-the-middle approach:
    // All paths from (0, 0) to (m-1, n-1) have length m + n - 1.
    // Let k = floor((m + n - 1) / 2) be the "mid-path" length (number of steps taken from start).
    // The cells (i, j) such that i + j = k are potential meeting points.

    const target_sum = m + n - 2;
    const half_sum = Math.floor(target_sum / 2);

    // 1. Forward search from (0, 0)
    // forward_xor[s] stores a Set of all possible XOR sums to reach any cell (i, j) such that i + j = s.
    // We only need to store the XOR sums for cells where i + j = half_sum.
    // A map from coordinate sum 's' to a Set of XOR values achieved at that sum.
    const forward_xor = new Map(); // Map<sum_i_j, Set<xor_value>>

    // Initialize for the start cell (0, 0)
    let q = [[0, 0, grid[0][0]]]; // [row, col, current_xor]
    forward_xor.set(0, new Set([grid[0][0]]));

    let head = 0;
    while(head < q.length) {
        const [r, c, current_xor] = q[head++];
        const current_sum = r + c;

        if (current_sum >= half_sum) {
            // If we passed the halfway point, we don't explore further for the forward phase
            continue;
        }

        // Move Right
        if (c + 1 < n) {
            const nr = r;
            const nc = c + 1;
            const next_xor = current_xor ^ grid[nr][nc];
            const next_sum = nr + nc;

            if (!forward_xor.has(next_sum)) {
                forward_xor.set(next_sum, new Set());
            }
            if (!forward_xor.get(next_sum).has(next_xor)) {
                forward_xor.get(next_sum).add(next_xor);
                q.push([nr, nc, next_xor]);
            }
        }

        // Move Down
        if (r + 1 < m) {
            const nr = r + 1;
            const nc = c;
            const next_xor = current_xor ^ grid[nr][nc];
            const next_sum = nr + nc;

            if (!forward_xor.has(next_sum)) {
                forward_xor.set(next_sum, new Set());
            }
            if (!forward_xor.get(next_sum).has(next_xor)) {
                forward_xor.get(next_sum).add(next_xor);
                q.push([nr, nc, next_xor]);
            }
