    // In the backward path, the XOR sum is accumulated from the end.
    // If the forward path XOR is X_f and the backward path XOR is X_b (including grid[m-1][n-1]),
    // the total path XOR is X_f XOR X_b XOR grid[i][j] (since grid[i][j] is counted in both).
    // Wait, this is complex because the meeting point XOR depends on how we define the backward accumulation.

    // Simpler approach for meet-in-the-middle:
    // Forward: Start at (0, 0). Store XORs for all cells (r, c) such that r + c = half_sum.
    // Backward: Start at (m-1, n-1). Store XORs for all cells (r, c) such that r + c = half_sum.
    // When meeting at (r, c), if the forward XOR is $X_f$ and the backward XOR (calculated from end to (r,c)) is $X_b$,
    // the total XOR is $X_f \oplus X_b \oplus grid[r][c]$.

    const backward_xor = new Map(); // Map<sum_i_j, Set<xor_value>>

    // Initialize for the end cell (m-1, n-1)
    let q_b = [[m - 1, n - 1, grid[m - 1][n - 1]]]; // [row, col, current_xor]
    backward_xor.set(target_sum, new Set([grid[m - 1][n - 1]]));

    head = 0;
    while(head < q_b.length) {
        const [r, c, current_xor] = q_b[head++];
        const current_sum = r + c;

        if (current_sum <= half_sum) {
            // If we passed the halfway point going backwards, we stop for the backward phase
            // because we are interested in cells where r+c = half_sum.
            // Note: The meeting points must satisfy r+c >= half_sum because the total path length is m+n-1.
            // If we reach a cell with sum < half_sum, it means we've passed the true midpoint.
            if (current_sum < half_sum) continue;
        }

        // Potential previous cells (moving up or left in grid)
        const neighbors = [];
        if (r - 1 >= 0) neighbors.push([r - 1, c]); // Came from up
        if (c - 1 >= 0) neighbors.push([r, c - 1]); // Came from left

        for (const [pr, pc] of neighbors) {
            const prev_xor = current_xor ^ grid[pr][pc];
            const prev_sum = pr + pc;

            if (!backward_xor.has(prev_sum)) {
                backward_xor.set(prev_sum, new Set());
            }
            if (!backward_xor.get(prev_sum).has(prev_xor)) {
                backward_xor.get(prev_sum).add(prev_xor);
                q_b.push([pr, pc, prev_xor]);
            }
        }
    }

    // 3. Combine results
    let min_xor = Infinity;

    if (forward_xor.has(half_sum) && backward_xor.has(half_sum)) {
        const forward_set = forward_xor.get(half_sum);
        const backward_set = backward_xor.get(half_sum);

        // Iterate over all meeting cells (r, c) such that r + c = half_sum
        for (let r = 0; r < m; r++) {
            const c = half_sum - r;
            if (c < 0 || c >= n) continue;

            // Check if this specific cell (r, c) was reached in both sets.
            // The DP structure above stores XOR sums *at* sum 's', not tied to a specific cell (r, c).
            // This means we cannot easily ensure the paths meet *exactly* at (r, c) with the stored XORs.

            // Reverting to the simpler interpretation for the meet-in-the-middle:
            // We assume the sets in forward_xor.get(half_sum) and backward_xor.get(half_sum) 
