        // Max value is 1023 (10 bits). The number of possible XOR sums is at most 1024.

        // Let DP[r][c] be the Set of all possible XOR sums to reach (r, c).
        const dp = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

        dp[0][0].add(grid[0][0]);

        for (let r = 0; r < m; r++) {
            for (let c = 0; c < n; c++) {
                if (r === 0 && c === 0) continue;

                const current_cell_val = grid[r][c];
                const possible_xors = new Set();

                // From Up
                if (r > 0) {
                    for (const prev_xor of dp[r - 1][c]) {
                        possible_xors.add(prev_xor ^ current_cell_val);
                    }
                }

                // From Left
                if (c > 0) {
                    for (const prev_xor of dp[r][c - 1]) {
                        possible_xors.add(prev_xor ^ current_cell_val);
                    }
                }

                dp[r][c] = possible_xors;
            }
        }

        // The answer is the minimum element in the set at the target cell.
        const final_xors = dp[m - 1][n - 1];
        if (final_xors.size === 0) {
            // Should not happen given constraints
            return -1;
        }

        let result = Infinity;
        for (const xor_val of final_xors) {
            result = Math.min(result, xor_val);
        }
        return result;
    }

