        int n = grid[0].length;

        // dp[r][c] stores the Set of all possible XOR sums to reach cell (r, c).
        // Since grid[i][j] <= 1023, the XOR sum will also be <= 1023.
        // We use Integer for XOR values as they fit within standard integers.
        Set<Integer>[][] dp = new HashSet[m][n];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dp[i][j] = new HashSet<>();
            }
        }

        // Initialize the starting cell (0, 0)
        dp[0][0].add((int) grid[0][0]);

        // Iterate through the grid
        for (int r = 0; r < m; r++) {
            for (int c = 0; c < n; c++) {
                if (r == 0 && c == 0) continue;

                int currentCellValue = (int) grid[r][c];
                Set<Integer> possibleXors = new HashSet<>();

                // From Up (r-1, c)
                if (r > 0) {
                    for (int prevXor : dp[r - 1][c]) {
                        possibleXors.add(prevXor ^ currentCellValue);
                    }
                }

                // From Left (r, c-1)
                if (c > 0) {
                    for (int prevXor : dp[r][c - 1]) {
                        possibleXors.add(prevXor ^ currentCellValue);
                    }
                }

                dp[r][c] = possibleXors;
            }
        }

        // Find the minimum XOR value at the target cell (m-1, n-1)
        Set<Integer> finalXors = dp[m - 1][n - 1];

        if (finalXors.isEmpty()) {
            // Should not happen based on problem constraints
            return -1; 
        }

        int minXor = Integer.MAX_VALUE;
        for (int xorVal : finalXors) {
